/* SQL ID : UsrUserInfoDAO.selectForLogin 설 명 : 사용자의 정보 조회 */ SELECT A.USER_ID , A.USER_RPRS_ID , A.USERNM , A.USER_ENNM , A.ORG_ID , A.USER_ID_STSCD , A.LGN_MTHD_GBNCD , A.USER_ID_ENCPSWD , B.TMP_PSWD , 'Y' AS PSWD_CHG_REQ_YN , 'Y' AS LOGIN_USE_YN , A.EXAM_SPRT_APLY_TYCD , A.DEPT_ID --, (SELECT aa.UNIV_ID FROM TB_LMS_USER_AC_RCD aa WHERE aa.USER_ID = A.USER_ID) AS UNIV_CD , (SELECT bb.CNTCT FROM TB_LMS_USER_CNTCT bb WHERE bb.USER_CNTCT_ID = A.USER_ID) AS MOBILE_NO , A.USER_ENV_STNG_CTS , A.USER_ID_STSCD , A.PHOTO_FILE_ID FROM TB_LMS_USER A LEFT OUTER JOIN TB_LMS_USER_TMP_PSWD B ON A.USER_ID = B.USER_ID LEFT OUTER JOIN TB_LMS_USER_SNS_LGN C ON A.USER_ID = C.USER_ID WHERE A.USER_ID_STSCD = 'APRV_CMPTN' AND (B.PSWD_CHG_CMPTNYN = 'N' OR B.PSWD_CHG_CMPTNYN IS NULL)
AND (A.USER_ID = #{userId} OR A.USER_RPRS_ID = #{userRprsId})
AND A.ORG_ID = #{orgId}
AND A.ORG_ID = #{orgId}
AND C.SNS_KEY = #{snsKey} AND C.SNS_GBNCD = #{snsDiv}

/* SQL ID : UsrUserInfoDAO.selectForLoginCheck 설 명 : 사용자의 정보 조회 */
SELECT A.USER_ID , A.USERNM , A.USER_ENNM , A.ORG_ID , B.USER_ID , B.USER_ENCPSWD , B.TMP_PASS , B.ADMIN_LOGIN_ACPT_DIV_CD , B.LOGIN_FAIL_DTTM , B.LGN_CNTNU_FAIL_CNT , B.LAST_LOGIN_DTTM , B.LOGIN_CNT , B.USER_ACNT_STSCD , CASE WHEN SYSDATE >= TO_DATE(NVL(B.PSWD_CHG_REQ_DTTM, B.MOD_DTTM), 'YYYYMMDDHH24MISS') THEN 'Y' ELSE 'N' END AS PSWD_CHG_REQ_YN , CASE WHEN B.LGN_CNTNU_FAIL_CNT >= (SELECT STNG_VL FROM TB_SYS_CFG WHERE STNG_CTGRCD = 'LOGIN' AND STNG_CD = 'FAILCNT') THEN CASE WHEN TO_CHAR(SYSDATE, 'YYYYMMDDHH24MISS') - NVL(B.LOGIN_FAIL_DTTM, '19900101000001') < ( SELECT STNG_VL FROM TB_SYS_CFG WHERE STNG_CTGRCD = 'LOGIN' AND STNG_CD = 'GAPTIME') THEN 'N' ELSE 'Y' END ELSE 'Y' END AS LOGIN_USE_YN , A.DISABLILITY_YN , A.EXAM_SPRT_APLY_TYCD , A.PHT_FILE AS PHT_FILE_BYTE , A.DEPT_CD FROM TB_LMS_USR A WHERE A.USER_ID = B.USER_ID AND B.USER_ACNT_STSCD = 'U'
AND (B.USER_ID = #{userId} or B.USER_ID = #{userId})
AND A.ORG_ID = #{orgId}
AND A.ORG_ID = #{orgId}
AND B.SNS_KEY = #{snsKey} AND B.SNS_GBNCD = #{snsDiv}
AND B.USER_ENCPSWD = #{userPass}

