SET USERNM = #{userNm}

    , USER_ENNM = #{userNmEng}


    , PRFIL_PHOTO_FILE_ID = #{photoFileSn}


    , MOBILE_NO = #{mobileNo}


    , EMAIL = #{email}


    , DEPT_CD = #{deptCd}


    , DEPTNM = #{deptNm}


    , EMAIL_RECV = #{emailRecv}


    , SMS_RECV = #{smsRecv}


    , DISABLILITY_YN = #{disablilityYn}


    , MN_DSBL_GRDCD = #{disabilityLv}


    , MN_DSBL_CD = #{disabilityCd}


    , EXAM_SPRT_APLY_TYCD = #{disablilityExamYn}


    , USER_GRADE = #{userGrade}


    , TKN_EML = #{tcEmail}


    , TC_ID = #{tcId}


    , TC_ROLE = #{tcRole}


    , PHT_FILE = #{phtFileByte}


    , PHT_FILE = NULL

WHERE USER_ID = #{userId}

