SELECT ROW_NUMBER() OVER (ORDER BY A.USERNM) AS LINE_NO , A.USER_PRFIL_ID , A.USERNM , A.ORG_ID -- , A.MOBILE_NO -- , A.EMAIL , A.DEPT_CD -- , A.DEPTNM -- , A.DISABLILITY_YN -- , A.SCHREG_GBN -- , A.OFCE_TELNO , MSTYN FROM TB_LMS_USER_PRFIL A JOIN TB_LMS_USER_ACNT B ON A.USER_PRFIL_ID = B.USER_ID AND B.USER_ID_STSCD = 'U' WHERE A.ORG_ID = #{orgId}
AND A.DEPT_CD = #{deptCd}
AND EXISTS ( SELECT 1 FROM TB_LMS_USER_AUTHRT WHERE USER_AUTHRT_ID = #{authGrpCd} AND USER_ID = A.USER_ID )
AND EXISTS ( SELECT 1 FROM TB_LMS_USER_AUTHRT WHERE MENU_TYCD = #{menuType} AND USER_ID = A.USER_ID )
AND EXISTS ( SELECT 1 FROM TB_LMS_USER_AUTHRT WHERE MENU_TYCD IN
#{item}
AND USER_AUTHRT_ID = A.USER_PRFIL_ID )
AND ( LOWER(A.USER_PRFIL_ID) LIKE FN_LIKE_VAL(LOWER(#{searchValue})) OR LOWER(A.USERNM) LIKE FN_LIKE_VAL(LOWER(#{searchValue})) OR LOWER(( SELECT CDNM FROM TB_LMS_CMMN_CD WHERE ORG_ID = #{orgId} AND CD = A.DEPT_CD AND USEYN = 'Y' )) LIKE FN_LIKE_VAL(LOWER(#{searchValue})) )
AND A.SCHREG_GBN_CD = #{schregGbnCd} AND EXISTS ( SELECT 1 FROM TB_LMS_USER_AUTHRT WHERE USER_AUTHRT_ID = 'USR' AND USER_ID = A.USER_ID )

