mapper.insert:
/*
SQL ID : UsrUserInfoDAO.insert
설 명 : 사용자 정보 등록
*/
INSERT INTO TB_LMS_USR (
USER_ID
, DEPT_CD
, ORG_ID
, DEPTNM
, PRFIL_PHOTO_FILE_ID
, DUP_INFO
, USERNM
, USER_ENNM
, MOBILE_NO
, EMAIL
, DISABLILITY_YN
, MN_DSBL_GRDCD
, MN_DSBL_CD
, EXAM_SPRT_APLY_TYCD
, SMS_RECV
, EMAIL_RECV
, MSG_RECV
, USER_GRADE
, TKN_EML
, TC_PW
, TC_ID
, TC_ROLE
, SCHREG_GBN_CD
, SCHREG_GBN
, OFCE_TELNO
, USER_STNG
) VALUES (
#{userId}
, CASE #{deptCd} WHEN '' THEN NULL ELSE #{deptCd} END
, #{orgId}

    , #{deptNm}


    , (SELECT DEPTNM FROM TB_HOME_USER_DEPT_CD WHERE ORG_ID = #{orgId} AND DEPT_CD = #{deptCd})

, #{photoFileSn}
, #{dupInfo}
, #{userNm}
, CASE #{userNmEng} WHEN '' THEN NULL ELSE #{userNmEng} END
, CASE #{mobileNo} WHEN '' THEN NULL ELSE #{mobileNo} END
, CASE #{email} WHEN '' THEN NULL ELSE #{email} END
, NVL(#{disablilityYn}, 'N')
, CASE #{disabilityLv} WHEN '' THEN NULL ELSE #{disabilityLv} END
, CASE #{disabilityCd} WHEN '' THEN NULL ELSE #{disabilityCd} END
, NVL(#{disablilityExamYn}, 'N')
, #{smsRecv}
, #{emailRecv}
, #{msgRecv}
, #{userGrade}
, #{tcEmail}
, #{tcPw}
, #{tcId}
, #{tcRole}
, #{schregGbnCd}
, #{schregGbn}
, #{ofceTelno}
, #{userConf}
)

mapper.select:
/*
SQL ID : UsrUserInfoDAO.selectSearchId
설 명 : 사용자의 이름과 이메일로 사용자 정보 검색
*/
SELECT B.USER_ID
, A.USER_ID
, A.USERNM
, A.USER_ENNM
, A.EMAIL
, A.DEPT_CD
, B.FRST_INQ_DTTM
FROM TB_LMS_USR A, TB_LMS_USER_ACNT B
WHERE A.USER_ID = B.USER_ID
AND B.USER_ACNT_STSCD = 'U'

    AND A.USERNM = #{userNm}


    AND B.USER_ID = #{userId}


    AND A.ORG_ID = #{orgId}


    AND A.EMAIL = #{email}


    AND A.MOBILE_NO = #{mobileNo}


    AND A.USER_ID = #{userId}

LIMIT 0, 1

/* SQL ID : UsrUserInfoDAO.listSearchByStudent 설 명 : 사용자 목록 검색 ( 학생 ) */ SELECT ROW_NUMBER() OVER(ORDER BY Z.USERNM) AS LINE_NO , Z.* FROM ( SELECT (SELECT ORGNM FROM TB_LMS_ORG WHERE ORG_ID = A.ORG_ID) AS ORGNM, A.USER_ID, A.USERNM, A.USER_ENNM, A.DEPTNM, NVL(( SELECT SCYR FROM ( SELECT SCYR FROM TB_LMS_ATNDLC_SBJCT LS, TB_LMS_USR HUI WHERE LS.ATNDLC_STSCD = 'S' AND LS.AUDITYN = 'N' AND LS.USER_ID = HUI.USER_ID ORDER BY LS.SBJCT_ID DESC ) WHERE ROWNUM = 1 ), 'no') AS SCYR, A.SCHREG_GBN, A.ENTR_YY, COUNT(*) OVER() AS TOTAL_CNT -- 학생구분, 학적변동, 생년월일, 국적 추가 필요 FROM TB_LMS_USR A JOIN TB_LMS_USER_ACNT B ON A.USER_ID = B.USER_ID AND B.USER_ACNT_STSCD = 'U' WHERE A.USER_ID IN ( SELECT USER_ID FROM TB_LMS_USER_AUTHRT WHERE MENU_TYCD = 'STUDENT' GROUP BY USER_ID )
AND A.ORG_ID = #{orgId}
AND A.DEPT_CD = #{deptCd}
AND ( LOWER(A.USER_ID) LIKE FN_LIKE_VAL(LOWER(#{searchValue})) OR LOWER(A.USERNM) LIKE FN_LIKE_VAL(LOWER(#{searchValue})) OR LOWER(A.MOBILE_NO) LIKE FN_LIKE_VAL(LOWER(#{searchValue})) )
AND A.USER_ID IN ( SELECT USER_ID FROM TB_LMS_ATNDLC_SBJCT WHERE ATNDLC_STSCD = 'S' AND AUDITYN = 'N' AND SBJCT_ID IN (SELECT SBJCT_ID FROM SBJCT_PROF WHERE USER_ID = #{userId}) )
ORDER BY A.USERNM ) Z WHERE 1 = 1
AND Z.SCYR = #{userGrade}

