/*
    SQL ID : UsrUserInfoDAO.editUseYn
    설  명 : 학과/부서 관리 목록 > 사용여부 변경
 */

UPDATE TB_HOME_USER_DEPT_CD
SET USEYN    = #{useYn}
  , MDFR_ID  = #{mdfrId}
  , MOD_DTTM = FN_DTTM()
WHERE DEPT_CD = #{deptCd}

mapper.sql:
SELECT A.USER_ID , A.ORG_ID , MAX( CASE WHEN A.MENU_TYCD = 'ADMIN' THEN 0 WHEN A.MENU_TYCD = 'PROFESSOR' THEN 1 WHEN A.MENU_TYCD = 'STUDENT' THEN 2 END ) AS USER_ORDER FROM (
SELECT A.USER_ID , A.ORG_ID , B.MENU_TYCD FROM TB_LMS_USR A JOIN TB_LMS_USER_AUTHRT B ON A.USER_ID = B.USER_AUTHRT_ID AND B.MENU_TYCD = 'ADMIN'
AND A.ORG_ID = #{orgId}
AND B.USER_AUTHRT_ID = #{authGrpCd}
AND B.MENU_TYCD = #{menuType}
WHERE (A.STSCD IS NULL OR A.STSCD != 'N')
AND ( LOWER(A.USER_ID) LIKE FN_LIKE_VAL(LOWER(#{searchValue})) OR LOWER(A.USERNM) LIKE FN_LIKE_VAL(LOWER(#{searchValue})) OR LOWER(A.DEPTNM) LIKE FN_LIKE_VAL(LOWER(#{searchValue})) )
UNION ALL SELECT A.USER_ID , A.ORG_ID , B.MENU_TYCD FROM TB_LMS_USR A JOIN TB_LMS_USER_AUTHRT B ON A.USER_ID = B.USER_AUTHRT_ID AND B.MENU_TYCD = 'PROFESSOR'
AND A.ORG_ID = #{orgId}
AND B.USER_AUTHRT_ID = #{authGrpCd}
AND B.MENU_TYCD = #{menuType}
WHERE (A.STSCD IS NULL OR A.STSCD != 'N')
AND ( LOWER(A.USER_ID)LIKE FN_LIKE_VAL(LOWER(#{searchValue})) OR LOWER(A.USERNM) LIKE FN_LIKE_VAL(LOWER(#{searchValue})) OR LOWER(A.DEPTNM) LIKE FN_LIKE_VAL(LOWER(#{searchValue})) )
UNION ALL
SELECT A.USER_ID , A.ORG_ID , B.MENU_TYCD FROM TB_LMS_USR A JOIN TB_LMS_USER_AUTHRT B ON A.USER_ID = B.USER_AUTHRT_ID AND B.MENU_TYCD = 'STUDENT'
AND A.ORG_ID = #{orgId}
AND B.USER_AUTHRT_ID = #{authGrpCd}
AND B.MENU_TYCD = #{menuType}
WHERE 1=1
AND A.SCHREG_GBN_CD = #{schregGbnCd}
AND ( LOWER(A.USER_ID) LIKE FN_LIKE_VAL(LOWER(#{searchValue})) OR LOWER(A.USERNM) LIKE FN_LIKE_VAL(LOWER(#{searchValue})) OR LOWER(A.DEPTNM) LIKE FN_LIKE_VAL(LOWER(#{searchValue})) )
) A GROUP BY A.USER_ID, A.ORG_ID

mapper.select:
/* SQL ID : UsrUserInfoDAO.listPagingUserByMenuType 설 명 : 메뉴 구분별 사용자 목록 페이징 */
SELECT A.* , (SELECT MAX(SCYR) FROM TB_LMS_ATNDLC_SBJCT WHERE USER_ID = A.USER_ID AND ATNDLC_STSCD = 'S') AS SCYR , (SELECT LISTAGG(BB.CD, ',') WITHIN GROUP (ORDER BY BB.CD) FROM TB_LMS_USER_AUTHRT AA JOIN TB_ORG_CODE BB ON AA.USER_AUTHRT_ID = BB.CD AND BB.CTGRCD = 'USER_TYPE' AND BB.ORG_ID = ORG_ID WHERE AA.USER_ID = A.USER_ID ) AS USER_AUTHRT_ID , (SELECT LISTAGG(BB.CDNM, ',') WITHIN GROUP (ORDER BY BB.CDNM) FROM TB_LMS_USER_AUTHRT AA JOIN TB_ORG_CODE BB ON AA.USER_AUTHRT_ID = BB.CD AND BB.CTGRCD = 'USER_TYPE' AND BB.ORG_ID = ORG_ID AND BB.CD_OPTN = 'ADMIN' WHERE AA.USER_ID = A.USER_ID ) AS ADMIN_AUTH_GRP_NM , (SELECT LISTAGG(BB.CDNM, ',') WITHIN GROUP (ORDER BY BB.CDNM) FROM TB_LMS_USER_AUTHRT AA JOIN TB_ORG_CODE BB ON AA.USER_AUTHRT_ID = BB.CD AND BB.CTGRCD = 'USER_TYPE' AND BB.ORG_ID = ORG_ID WHERE AA.USER_ID = A.USER_ID AND NVL(BB.CD_OPTN, '') != 'ADMIN' ) AS WWW_AUTH_GRP_NM , CASE WHEN EXISTS(SELECT 1 FROM TB_HOME_USER_MGNT_DEPT WHERE USER_ID = A.USER_ID AND MSTYN = 'Y') THEN 'Y' ELSE 'N' END AS MSTYN
, (SELECT KNOU_USER_ID FROM TB_HOME_USER_ORG_RLTN WHERE USER_ID = A.USER_ID) AS KNOU_USER_ID , (SELECT BB.USERNM FROM TB_HOME_USER_ORG_RLTN AA, TB_LMS_USR BB WHERE AA.KNOU_USER_ID = BB.USER_ID AND AA.USER_ID = A.USER_ID) AS KNOU_USER_NM
FROM ( SELECT ROW_NUMBER() OVER(ORDER BY A.USER_ORDER, B.USERNM) AS LINE_NO , A.USER_ID , B.ORG_ID , B.USERNM , B.DEPTNM , B.MOBILE_NO , B.EMAIL , B.SCHREG_GBN FROM (
) A JOIN TB_LMS_USR B ON A.USER_ID = B.USER_ID ORDER BY A.USER_ORDER, B.USERNM ) A

/* SQL ID : UsrUserInfoDAO.listSearchByKnouUser 설 명 : 한사대 사용자 목록 검색(운영자,교수) */ SELECT A.USER_ID , A.USERNM , A.DEPTNM , C.USER_AUTHRT_ID , (SELECT GROUP_CONCAT(BB.CDNM) FROM TB_LMS_USER_AUTHRT AA JOIN TB_ORG_CODE BB ON AA.USER_AUTHRT_ID = BB.CD AND BB.CTGRCD = 'USER_TYPE' AND BB.ORG_ID = A.ORG_ID WHERE AA.USER_ID = A.USER_ID AND IFNULL(BB.CD_OPTN, '') != 'ADMIN' ) AS WWW_AUTH_GRP_NM FROM TB_LMS_USR AS A JOIN TB_LMS_USER_ACNT AS B ON A.USER_ID = B.USER_ID AND B.USER_ACNT_STSCD = 'U' JOIN TB_LMS_USER_AUTHRT AS C ON A.USER_ID = C.USER_ID AND C.MENU_TYCD IN ('PROFESSOR', 'ADMIN') WHERE 1=1 AND A.ORG_ID = #{orgId}
AND ( LOWER(A.USER_ID) LIKE CONCAT('%', LOWER(#{searchValue}), '%') OR LOWER(A.USERNM) LIKE CONCAT('%', LOWER(#{searchValue}), '%') )
ORDER BY A.USERNM

mapper.insert:
/*
     SQL ID : UsrUserInfoDAO.insertUserOrgRltn
     설  명 : 기관사용자 한사대 사용자 연결 저장
 */
INSERT INTO TB_HOME_USER_ORG_RLTN ( USER_ID
                                  , ORG_ID
                                  , KNOU_USER_ID
                                  , RGTR_ID
                                  , FRST_INQ_DTTM
                                  , MDFR_ID
                                  , MOD_DTTM)
VALUES ( #{userId}
       , #{orgId}
       , #{knouUserId}
       , #{rgtrId}
       , FN_DTTM()
       , #{rgtrId}
       , FN_DTTM())

mapper.update:
/*
     SQL ID : UsrUserInfoDAO.updateUserOrgRltn
     설  명 : 기관사용자 한사대 사용자 연결 수정
 */
UPDATE TB_HOME_USER_ORG_RLTN
SET KNOU_USER_ID = #{knouUserId}
  , MDFR_ID      = #{mdfrId}
  , MOD_DTTM     = FN_DTTM()
WHERE 1 = 1
  AND USER_ID = #{userId}
